diff --git a/src/wow/guild-store.ts b/src/wow/guild-store.ts
new file mode 100644
index 0000000..5e68b05
--- /dev/null
+++ b/src/wow/guild-store.ts
@@ -0,0 +1,74 @@
+export type GuildMember = {
+  guid: bigint;
+  name: string;
+  rankIndex: number;
+  level: number;
+  playerClass: number;
+  gender: number;
+  area: number;
+  status: number;
+  timeOffline: number;
+  publicNote: string;
+  officerNote: string;
+};
+
+export type GuildRoster = {
+  guildName: string;
+  motd: string;
+  guildInfo: string;
+  rankNames: string[];
+  members: GuildMember[];
+};
+
+export type GuildEvent = { type: "guild-roster"; roster: GuildRoster };
+
+export class GuildStore {
+  private members = new Map<bigint, GuildMember>();
+  private guildName = "";
+  private motd = "";
+  private guildInfo = "";
+  private rankNames: string[] = [];
+  private listener?: (event: GuildEvent) => void;
+
+  onEvent(cb: (event: GuildEvent) => void): void {
+    this.listener = cb;
+  }
+
+  setRoster(motd: string, guildInfo: string, members: GuildMember[]): void {
+    this.motd = motd;
+    this.guildInfo = guildInfo;
+    this.members.clear();
+    for (const m of members) {
+      this.members.set(m.guid, { ...m });
+    }
+    this.fire();
+  }
+
+  setGuildMeta(name: string, rankNames: string[]): void {
+    this.guildName = name;
+    this.rankNames = rankNames;
+    if (this.members.size > 0) this.fire();
+  }
+
+  get(): GuildRoster | undefined {
+    if (this.members.size === 0) return undefined;
+    return {
+      guildName: this.guildName,
+      motd: this.motd,
+      guildInfo: this.guildInfo,
+      rankNames: this.rankNames,
+      members: this.all(),
+    };
+  }
+
+  all(): GuildMember[] {
+    return [...this.members.values()].sort((a, b) =>
+      a.name.localeCompare(b.name),
+    );
+  }
+
+  private fire(): void {
+    const roster = this.get();
+    if (roster) this.listener?.({ type: "guild-roster", roster });
+  }
+}
