 872→+export function formatGuildRoster(roster: GuildRoster): string {
 873→+  const online = roster.members.filter(
 874→+    (m) => m.status !== GuildMemberStatus.OFFLINE,
 875→+  );
 876→+  const offline = roster.members.filter(
 877→+    (m) => m.status === GuildMemberStatus.OFFLINE,
 878→+  );
 879→+  const header = roster.guildName
 880→+    ? `[guild] ${roster.guildName} — ${online.length}/${roster.members.length} online`
 881→+    : `[guild] ${online.length}/${roster.members.length} online`;
 882→+  const lines: string[] = [header];
 883→+  if (roster.motd) lines.push(`  MOTD: ${roster.motd}`);
 884→+  if (roster.guildInfo) lines.push(`  Info: ${roster.guildInfo}`);
 885→+  for (const m of online) {
 886→+    const cls = CLASS_NAMES[m.playerClass] ?? `class ${m.playerClass}`;
 887→+    const rank = rankName(roster, m.rankIndex);
 888→+    lines.push(`  ${m.name} — ${rank}, Level ${m.level} ${cls}`);
 889→+  }
 890→+  for (const m of offline) {
 891→+    const rank = rankName(roster, m.rankIndex);
 892→+    const ago = formatOfflineTime(m.timeOffline);
 893→+    lines.push(`  ${m.name} — ${rank}, Offline (${ago})`);
 894→+  }
 895→+  return lines.join("\n");
 896→+}
