 900→+    type: "GUILD_ROSTER",
 901→+    guildName: roster.guildName,
 902→+    motd: roster.motd,
 903→+    guildInfo: roster.guildInfo,
 904→+    rankNames: roster.rankNames,
 905→+    count: roster.members.length,
 906→+    online: roster.members.filter((m) => m.status !== GuildMemberStatus.OFFLINE)
 907→+      .length,
 908→+    members: roster.members.map((m) => ({
 909→+      guid: `0x${m.guid.toString(16)}`,
 910→+      name: m.name,
 911→+      rank: rankName(roster, m.rankIndex),
 912→+      rankIndex: m.rankIndex,
 913→+      level: m.level,
 914→+      class: CLASS_NAMES[m.playerClass] ?? `class ${m.playerClass}`,
 915→+      status: m.status === GuildMemberStatus.OFFLINE ? "OFFLINE" : "ONLINE",
 916→+      area: m.area,
 917→+      publicNote: m.publicNote,
 918→+      officerNote: m.officerNote,
 919→+    })),
 920→+  });
 921→+}
