1299→+export type GuildMember = {
1300→+  guid: bigint;
1301→+  name: string;
1302→+  rankIndex: number;
1303→+  level: number;
1304→+  playerClass: number;
1305→+  gender: number;
1306→+  area: number;
1307→+  status: number;
1308→+  timeOffline: number;
1309→+  publicNote: string;
1310→+  officerNote: string;
1311→+};
1312→+
1313→+export type GuildRoster = {
1314→+  guildName: string;
1315→+  motd: string;
1316→+  guildInfo: string;
1317→+  rankNames: string[];
1318→+  members: GuildMember[];
1319→+};
1320→+
1321→+export type GuildEvent = { type: "guild-roster"; roster: GuildRoster };
1322→+
1323→+export class GuildStore {
1324→+  private members = new Map<bigint, GuildMember>();
1325→+  private guildName = "";
1326→+  private motd = "";
1327→+  private guildInfo = "";
1328→+  private rankNames: string[] = [];
1329→+  private listener?: (event: GuildEvent) => void;
1330→+
1331→+  onEvent(cb: (event: GuildEvent) => void): void {
1332→+    this.listener = cb;
1333→+  }
1334→+
1335→+  setRoster(motd: string, guildInfo: string, members: GuildMember[]): void {
1336→+    this.motd = motd;
1337→+    this.guildInfo = guildInfo;
1338→+    this.members.clear();
1339→+    for (const m of members) {
1340→+      this.members.set(m.guid, { ...m });
1341→+    }
1342→+    this.fire();
1343→+  }
1344→+
1345→+  setGuildMeta(name: string, rankNames: string[]): void {
1346→+    this.guildName = name;
1347→+    this.rankNames = rankNames;
1348→+    if (this.members.size > 0) this.fire();
1349→+  }
1350→+
1351→+  get(): GuildRoster | undefined {
1352→+    if (this.members.size === 0) return undefined;
1353→+    return {
1354→+      guildName: this.guildName,
1355→+      motd: this.motd,
1356→+      guildInfo: this.guildInfo,
1357→+      rankNames: this.rankNames,
1358→+      members: this.all(),
1359→+    };
1360→+  }
1361→+
1362→+  all(): GuildMember[] {
1363→+    return [...this.members.values()].sort((a, b) =>
1364→+      a.name.localeCompare(b.name),
1365→+    );
1366→+  }
1367→+
1368→+  private fire(): void {
1369→+    const roster = this.get();
1370→+    if (roster) this.listener?.({ type: "guild-roster", roster });
1371→+  }
1372→+}
