 12→
 13→const CHAT_TYPE_LABELS: Record<number, string> = {
 14→  [ChatType.SYSTEM]: "system",
 15→  [ChatType.SAY]: "say",
 16→  [ChatType.PARTY]: "party",
 17→  [ChatType.RAID]: "raid",
 18→  [ChatType.GUILD]: "guild",
 19→  [ChatType.OFFICER]: "officer",
 20→  [ChatType.YELL]: "yell",
 21→  [ChatType.WHISPER]: "whisper from",
