 23→  [ChatType.EMOTE]: "emote",
 24→  [ChatType.CHANNEL]: "channel",
 25→  [ChatType.RAID_LEADER]: "raid leader",
 26→  [ChatType.RAID_WARNING]: "raid warning",
 27→  [ChatType.PARTY_LEADER]: "party leader",
 28→  [ChatType.ROLL]: "roll",
