 30→
 31→export function formatMessage(msg: ChatMessage): string {
 32→  const message = stripColorCodes(msg.message);
 33→  const label = CHAT_TYPE_LABELS[msg.type] ?? `type ${msg.type}`;
 34→
 35→  if (msg.type === ChatType.WHISPER) {
 36→    return `[whisper from ${msg.sender}] ${message}`;
 37→  }
 38→  if (msg.type === ChatType.WHISPER_INFORM) {
 39→    return `[whisper to ${msg.sender}] ${message}`;
 40→  }
 41→  if (
 42→    msg.type === ChatType.SYSTEM &&
 43→    (msg.origin === "server" || msg.origin === "notification")
 44→  ) {
 45→    return `[server] ${message}`;
 46→  }
 47→  if (msg.type === ChatType.SYSTEM) {
 48→    return `[system] ${message}`;
 49→  }
 50→  if (msg.type === ChatType.ROLL) {
 51→    return `[roll] ${msg.sender} ${message}`;
 52→  }
 53→  if (msg.type === ChatType.CHANNEL && msg.channel) {
 54→    return `[${msg.channel}] ${msg.sender}: ${message}`;
 55→  }
 56→  return `[${label}] ${msg.sender}: ${message}`;
 57→}
 58→
 59→const JSON_TYPE_LABELS: Record<number, string> = {
 60→  [ChatType.SYSTEM]: "SYSTEM",
 61→  [ChatType.SAY]: "SAY",
 62→  [ChatType.PARTY]: "PARTY",
 63→  [ChatType.RAID]: "RAID",
 64→  [ChatType.GUILD]: "GUILD",
 65→  [ChatType.OFFICER]: "OFFICER",
 66→  [ChatType.YELL]: "YELL",
 67→  [ChatType.WHISPER]: "WHISPER_FROM",
 68→  [ChatType.WHISPER_INFORM]: "WHISPER_TO",
 69→  [ChatType.EMOTE]: "EMOTE",
 70→  [ChatType.CHANNEL]: "CHANNEL",
 71→  [ChatType.RAID_LEADER]: "RAID_LEADER",
