 73→  [ChatType.PARTY_LEADER]: "PARTY_LEADER",
 74→  [ChatType.ROLL]: "ROLL",
 75→};
 76→
 77→export function formatMessageObj(msg: ChatMessage): LogEntry {
 78→  const type =
 79→    msg.origin === "server"
 80→      ? "SERVER_BROADCAST"
 81→      : msg.origin === "notification"
 82→        ? "NOTIFICATION"
 83→        : (JSON_TYPE_LABELS[msg.type] ?? `TYPE_${msg.type}`);
 84→  const obj: LogEntry = {
 85→    type,
 86→    sender: msg.sender,
