 49→function ensureNameQuery(conn: WorldConn, guid: bigint): void {
 50→  const guidLow = Number(guid & 0xffffffffn);
 51→  if (conn.pendingNameQueries.has(`player:${guidLow}`)) return;
 52→  conn.pendingNameQueries.add(`player:${guidLow}`);
 53→  sendPacket(
 54→    conn,
 55→    GameOpcode.CMSG_NAME_QUERY,
 56→    buildNameQuery(guidLow, Number((guid >> 32n) & 0xffffffffn)),
 57→  );
 58→}
