 90→export function resolveAndDeliver(conn: WorldConn, raw: RawChatMessage): void {
 91→  if (raw.senderGuidLow === 0) {
 92→    deliverMessage(conn, raw, "");
 93→    return;
 94→  }
 95→
 96→  if (conn.ignoreStore.has(raw.senderGuidLow)) return;
 97→
 98→  const cached = conn.nameCache.get(raw.senderGuidLow);
 99→  if (cached !== undefined) {
100→    deliverMessage(conn, raw, cached);
101→    return;
102→  }
103→
104→  const pending = conn.pendingMessages.get(raw.senderGuidLow);
105→  if (pending) {
106→    pending.push(raw);
107→  } else {
108→    conn.pendingMessages.set(raw.senderGuidLow, [raw]);
109→    sendPacket(
110→      conn,
111→      GameOpcode.CMSG_NAME_QUERY,
112→      buildNameQuery(raw.senderGuidLow, raw.senderGuidHigh),
113→    );
114→  }
115→}
