138→  conn: WorldConn,
139→  r: PacketReader,
140→): void {
141→  const result = parseNameQueryResponse(r);
142→
143→  const name = result.found && result.name ? result.name : "";
144→  conn.pendingNameQueries.delete(`player:${result.guidLow}`);
145→  if (result.found && result.name) {
146→    conn.nameCache.set(result.guidLow, result.name);
147→    for (const entity of conn.entityStore.all()) {
148→      if (
149→        entity.objectType === ObjectType.PLAYER &&
150→        Number(entity.guid & 0xffffffffn) === result.guidLow &&
151→        !entity.name
152→      ) {
153→        conn.entityStore.setName(entity.guid, result.name);
154→      }
155→    }
156→    for (const friend of conn.friendStore.all()) {
157→      if (
158→        Number(friend.guid & 0xffffffffn) === result.guidLow &&
159→        !friend.name
160→      ) {
161→        conn.friendStore.setName(friend.guid, result.name);
162→      }
163→    }
164→    for (const entry of conn.ignoreStore.all()) {
165→      if (Number(entry.guid & 0xffffffffn) === result.guidLow && !entry.name) {
166→        conn.ignoreStore.setName(entry.guid, result.name);
167→      }
168→    }
169→  }
170→
171→  const pending = conn.pendingMessages.get(result.guidLow);
172→  if (!pending) return;
173→  for (const raw of pending) deliverMessage(conn, raw, name);
174→  conn.pendingMessages.delete(result.guidLow);
175→}
