344→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
345→  const entries = parseUpdateObject(r);
346→  for (const entry of entries) {
347→    switch (entry.type) {
348→      case "create": {
349→        const { _changed: _co, ...objFields } = extractObjectFields(
350→          entry.fields,
351→        );
352→        let extraFields: Record<string, unknown> = {};
353→        if (
354→          entry.objectType === ObjectType.UNIT ||
355→          entry.objectType === ObjectType.PLAYER
356→        ) {
357→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
358→          extraFields = rest;
359→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
360→          const { _changed: _cg, ...rest } = extractGameObjectFields(
361→            entry.fields,
362→          );
363→          extraFields = rest;
364→        }
365→        const cachedName = lookupCachedName(
366→          conn,
367→          entry.guid,
368→          entry.objectType,
369→          objFields.entry,
370→        );
371→        conn.entityStore.create(entry.guid, entry.objectType, {
372→          ...objFields,
373→          ...extraFields,
374→          ...(cachedName ? { name: cachedName } : {}),
375→          ...(entry.position ? { position: entry.position } : {}),
376→          rawFields: new Map(entry.fields),
377→        } as any);
378→        if (!cachedName) {
379→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
380→        }
381→        break;
382→      }
383→      case "values": {
384→        const entity = conn.entityStore.get(entry.guid);
385→        if (!entity) break;
386→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
387→        let extraFields: Record<string, unknown> = {};
388→        if (
389→          entity.objectType === ObjectType.UNIT ||
390→          entity.objectType === ObjectType.PLAYER
391→        ) {
392→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
393→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
394→          extraFields = extractGameObjectFields(entry.fields);
395→        }
396→        const allChanged = [
397→          ...(objFields._changed || []),
398→          ...((extraFields as any)._changed || []),
399→        ];
400→        const merged: Record<string, unknown> = {};
401→        for (const key of allChanged) {
402→          if (key in extraFields) merged[key] = (extraFields as any)[key];
403→          else if (key in objFields) merged[key] = (objFields as any)[key];
404→        }
405→        conn.entityStore.update(entry.guid, merged);
406→        for (const [k, v] of entry.fields) {
407→          const existing = conn.entityStore.get(entry.guid);
408→          if (existing) existing.rawFields.set(k, v);
409→        }
410→        break;
411→      }
412→      case "movement": {
413→        conn.entityStore.setPosition(entry.guid, entry.position);
414→        break;
415→      }
416→      case "outOfRange": {
417→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
418→        break;
419→      }
420→      case "nearObjects": {
421→        break;
422→      }
423→    }
424→  }
425→}
