427→export function handleCompressedUpdateObject(
428→  conn: WorldConn,
429→  r: PacketReader,
430→): void {
431→  const uncompressedSize = r.uint32LE();
432→  const compressed = r.bytes(r.remaining);
433→  const decompressed = inflateSync(compressed);
434→  if (decompressed.length !== uncompressedSize) {
435→    throw new Error(
436→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
437→    );
438→  }
439→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
440→}
