448→export function lookupCachedName(
449→  conn: WorldConn,
450→  guid: bigint,
451→  objectType: number,
452→  entry: number | undefined,
453→): string | undefined {
454→  if (objectType === ObjectType.PLAYER) {
455→    const guidLow = Number(guid & 0xffffffffn);
456→    return conn.nameCache.get(guidLow);
457→  }
458→  if (entry === undefined) return undefined;
459→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
460→  if (objectType === ObjectType.GAMEOBJECT)
461→    return conn.gameObjectNameCache.get(entry);
462→  return undefined;
463→}
