465→export function queryEntityName(
466→  conn: WorldConn,
467→  guid: bigint,
468→  objectType: number,
469→  entry: number | undefined,
470→): void {
471→  if (objectType === ObjectType.PLAYER) {
472→    const guidLow = Number(guid & 0xffffffffn);
473→    const key = `player:${guidLow}`;
474→    if (conn.pendingNameQueries.has(key)) return;
475→    conn.pendingNameQueries.add(key);
476→    const w = new PacketWriter();
477→    w.uint64LE(guid);
478→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
479→    return;
480→  }
481→  if (entry === undefined) return;
482→  const key = `${objectType}:${entry}`;
483→  if (conn.pendingNameQueries.has(key)) return;
484→  conn.pendingNameQueries.add(key);
485→  if (objectType === ObjectType.UNIT) {
486→    sendPacket(
487→      conn,
488→      GameOpcode.CMSG_CREATURE_QUERY,
489→      buildCreatureQuery(entry, guid),
490→    );
491→    return;
492→  }
493→  if (objectType === ObjectType.GAMEOBJECT) {
494→    sendPacket(
495→      conn,
496→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
497→      buildGameObjectQuery(entry, guid),
498→    );
499→    return;
500→  }
501→}
