554→export function handleContactList(conn: WorldConn, r: PacketReader): void {
555→  const list = parseContactList(r);
556→  const friends: FriendEntry[] = [];
557→  for (const contact of list.contacts) {
558→    if (!(contact.flags & SocialFlag.FRIEND)) continue;
559→    const guidLow = Number(contact.guid & 0xffffffffn);
560→    const name = conn.nameCache.get(guidLow) ?? "";
561→    friends.push({
562→      guid: contact.guid,
563→      name,
564→      note: contact.note,
565→      status: contact.status ?? 0,
566→      area: contact.area ?? 0,
567→      level: contact.level ?? 0,
568→      playerClass: contact.playerClass ?? 0,
569→    });
570→    if (!name) ensureNameQuery(conn, contact.guid);
571→  }
572→  conn.friendStore.set(friends);
573→
574→  const ignored: IgnoreEntry[] = [];
575→  for (const contact of list.contacts) {
576→    if (!(contact.flags & SocialFlag.IGNORED)) continue;
577→    const guidLow = Number(contact.guid & 0xffffffffn);
578→    const name = conn.nameCache.get(guidLow) ?? "";
579→    ignored.push({ guid: contact.guid, name });
580→    if (!name) ensureNameQuery(conn, contact.guid);
581→  }
582→  conn.ignoreStore.set(ignored);
583→}
