585→export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
586→  const packet = parseFriendStatus(r);
587→  const guidLow = Number(packet.guid & 0xffffffffn);
588→
589→  switch (packet.result) {
590→    case FriendResult.ADDED_ONLINE:
591→    case FriendResult.ADDED_OFFLINE: {
592→      const name = conn.nameCache.get(guidLow) ?? "";
593→      conn.friendStore.add({
594→        guid: packet.guid,
595→        name,
596→        note: packet.note ?? "",
597→        status: packet.status ?? 0,
598→        area: packet.area ?? 0,
599→        level: packet.level ?? 0,
600→        playerClass: packet.playerClass ?? 0,
601→      });
602→      if (!name) ensureNameQuery(conn, packet.guid);
603→      break;
604→    }
605→    case FriendResult.ONLINE:
606→      conn.friendStore.update(packet.guid, {
607→        status: packet.status ?? FriendStatus.ONLINE,
608→        area: packet.area ?? 0,
609→        level: packet.level ?? 0,
610→        playerClass: packet.playerClass ?? 0,
611→      });
612→      break;
613→    case FriendResult.OFFLINE:
614→      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
615→      break;
616→    case FriendResult.REMOVED:
617→      conn.friendStore.remove(packet.guid);
618→      break;
619→    case FriendResult.IGNORE_ADDED: {
620→      const name = conn.nameCache.get(guidLow) ?? "";
621→      conn.ignoreStore.add({ guid: packet.guid, name });
622→      if (!name) ensureNameQuery(conn, packet.guid);
623→      break;
624→    }
625→    case FriendResult.IGNORE_REMOVED:
626→      conn.ignoreStore.remove(packet.guid);
627→      break;
628→    case FriendResult.IGNORE_FULL:
629→    case FriendResult.IGNORE_SELF:
630→    case FriendResult.IGNORE_NOT_FOUND:
631→    case FriendResult.IGNORE_ALREADY:
632→    case FriendResult.IGNORE_AMBIGUOUS: {
633→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
634→      conn.onIgnoreEvent?.({
635→        type: "ignore-error",
636→        result: packet.result,
637→        name,
638→      });
639→      break;
640→    }
641→    default: {
642→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
643→      conn.onFriendEvent?.({
644→        type: "friend-error",
645→        result: packet.result,
646→        name,
647→      });
648→      break;
649→    }
650→  }
651→}
