188→  onPacketError(cb: (opcode: number, err: Error) => void): void;
189→  getNearbyEntities(): Entity[];
190→  getFriends(): FriendEntry[];
191→  addFriend(name: string): void;
192→  removeFriend(name: string): void;
193→  sendRoll(min: number, max: number): void;
194→  onFriendEvent(cb: (event: FriendEvent) => void): void;
195→  getIgnored(): IgnoreEntry[];
196→  addIgnore(name: string): void;
197→  removeIgnore(name: string): void;
198→  onIgnoreEvent(cb: (event: IgnoreEvent) => void): void;
199→  requestGuildRoster(): Promise<GuildRoster | undefined>;
200→  onGuildEvent(cb: (event: GuildEvent) => void): void;
201→};
202→
203→export type WorldConn = {
204→  socket: Socket;
205→  dispatch: OpcodeDispatch;
206→  buf: AccumulatorBuffer;
207→  arc4?: Arc4;
208→  startTime: number;
209→  pendingHeader?: { size: number; opcode: number };
210→  nameCache: Map<number, string>;
211→  pendingMessages: Map<number, RawChatMessage[]>;
212→  channels: string[];
213→  lastChatMode: ChatMode;
214→  onMessage?: (msg: ChatMessage) => void;
215→  selfName: string;
216→  selfGuidLow: number;
217→  selfGuidHigh: number;
218→  partyMembers: Map<string, { guidLow: number; guidHigh: number }>;
219→  onGroupEvent?: (event: GroupEvent) => void;
220→  entityStore: EntityStore;
221→  creatureNameCache: Map<number, string>;
222→  gameObjectNameCache: Map<number, string>;
223→  onEntityEvent?: (event: EntityEvent) => void;
224→  onPacketError?: (opcode: number, err: Error) => void;
225→  pendingNameQueries: Set<string>;
226→  friendStore: FriendStore;
227→  onFriendEvent?: (event: FriendEvent) => void;
228→  ignoreStore: IgnoreStore;
229→  onIgnoreEvent?: (event: IgnoreEvent) => void;
230→  guildStore: GuildStore;
231→  guildId: number;
232→  onGuildEvent?: (event: GuildEvent) => void;
233→};
234→
235→function drainWorldPackets(conn: WorldConn): void {
236→  while (true) {
237→    if (!conn.pendingHeader) {
238→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
239→      conn.pendingHeader = decryptIncomingHeader(
240→        conn.buf.drain(INCOMING_HEADER_SIZE),
241→        conn.arc4,
242→      );
243→    }
244→    const bodySize = conn.pendingHeader.size - 2;
245→    if (conn.buf.length < bodySize) break;
246→
247→    const { opcode } = conn.pendingHeader;
248→    conn.pendingHeader = undefined;
249→    try {
250→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
251→    } catch (err) {
252→      if (err instanceof Error) {
253→        conn.onPacketError?.(opcode, err);
254→      }
255→    }
256→  }
257→}
