259→async function authenticateWorld(
260→  conn: WorldConn,
261→  config: ClientConfig,
262→  auth: AuthResult,
263→): Promise<void> {
264→  const challenge = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_CHALLENGE);
265→  challenge.uint32LE();
266→  const serverSeed = challenge.bytes(4);
267→
268→  const body = await buildWorldAuthPacket(
269→    config.account,
270→    auth.sessionKey,
271→    serverSeed,
272→    auth.realmId,
273→    config.clientSeed,
274→  );
275→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
276→  conn.arc4 = new Arc4(auth.sessionKey);
277→
278→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
279→  const status = resp.uint8();
280→  if (status !== 0x0c) {
281→    const names: Record<number, string> = {
282→      0x0d: "system error",
283→      0x15: "account in use",
284→    };
285→    const label = names[status] ?? `status 0x${status.toString(16)}`;
286→    throw new Error(`World auth failed: ${label}`);
287→  }
288→}
