290→async function selectCharacter(
291→  conn: WorldConn,
292→  config: ClientConfig,
293→): Promise<void> {
294→  sendPacket(conn, GameOpcode.CMSG_CHAR_ENUM);
295→
296→  const enumReader = await conn.dispatch.expect(GameOpcode.SMSG_CHAR_ENUM);
297→  const chars = parseCharacterList(enumReader);
298→  const char = chars.find(
299→    (c) => c.name.toLowerCase() === config.character.toLowerCase(),
300→  );
301→  if (!char) {
302→    throw new Error(
303→      `Character "${config.character}" not found. Available: ${chars.map((c) => c.name).join(", ")}`,
304→    );
305→  }
306→
307→  conn.selfName = char.name;
308→  conn.selfGuidLow = char.guidLow;
309→  conn.selfGuidHigh = char.guidHigh;
310→  conn.guildId = char.guildId;
311→
312→  const w = new PacketWriter();
313→  w.uint32LE(char.guidLow);
314→  w.uint32LE(char.guidHigh);
315→  sendPacket(conn, GameOpcode.CMSG_PLAYER_LOGIN, w.finish());
316→
317→  await conn.dispatch.expect(GameOpcode.SMSG_LOGIN_VERIFY_WORLD);
318→}
319→
320→function startPingLoop(
321→  conn: WorldConn,
322→  intervalMs: number,
323→): ReturnType<typeof setInterval> {
324→  return setInterval(() => {
325→    const w = new PacketWriter();
326→    w.uint32LE(0);
327→    w.uint32LE(0);
328→    sendPacket(conn, GameOpcode.CMSG_PING, w.finish());
329→  }, intervalMs);
330→}
