538→        sendEmote(message) {
539→          conn.lastChatMode = { type: "emote" };
540→          sendPacket(
541→            conn,
542→            GameOpcode.CMSG_MESSAGE_CHAT,
543→            buildChatMessage(ChatType.EMOTE, lang, message),
544→          );
545→        },
