675→        },
676→        getFriends() {
677→          return conn.friendStore.all();
678→        },
679→        addFriend(name) {
680→          sendPacket(
681→            conn,
682→            GameOpcode.CMSG_ADD_FRIEND,
683→            buildAddFriend(name, ""),
684→          );
685→        },
686→        removeFriend(name) {
687→          const friend = conn.friendStore.findByName(name);
688→          if (!friend) {
689→            conn.onMessage?.({
690→              type: ChatType.SYSTEM,
