700→          );
701→        },
702→        sendRoll(min, max) {
703→          sendPacket(
704→            conn,
705→            GameOpcode.MSG_RANDOM_ROLL,
706→            buildRandomRoll(min, max),
707→          );
708→        },
709→        onFriendEvent(cb) {
710→          conn.onFriendEvent = cb;
711→        },
712→        getIgnored() {
713→          return conn.ignoreStore.all();
714→        },
715→        addIgnore(name) {
716→          sendPacket(conn, GameOpcode.CMSG_ADD_IGNORE, buildAddIgnore(name));
717→        },
718→        removeIgnore(name) {
719→          const entry = conn.ignoreStore.findByName(name);
720→          if (!entry) {
721→            conn.onMessage?.({
722→              type: ChatType.SYSTEM,
723→              sender: "",
724→              message: `"${name}" is not on your ignore list.`,
725→            });
726→            return;
727→          }
728→          sendPacket(
729→            conn,
730→            GameOpcode.CMSG_DEL_IGNORE,
731→            buildDelIgnore(entry.guid),
732→          );
733→        },
734→        onIgnoreEvent(cb) {
735→          conn.onIgnoreEvent = cb;
736→        },
737→        async requestGuildRoster() {
738→          sendPacket(conn, GameOpcode.CMSG_GUILD_ROSTER);
739→          const rosterPromise = conn.dispatch.expect(
740→            GameOpcode.SMSG_GUILD_ROSTER,
741→          );
742→          let queryPromise: Promise<PacketReader> | undefined;
743→          if (conn.guildId) {
744→            sendPacket(
745→              conn,
746→              GameOpcode.CMSG_GUILD_QUERY,
747→              buildGuildQuery(conn.guildId),
748→            );
749→            queryPromise = conn.dispatch.expect(
750→              GameOpcode.SMSG_GUILD_QUERY_RESPONSE,
751→            );
752→          }
753→          handleGuildRoster(conn, await rosterPromise);
754→          if (queryPromise) handleGuildQueryResponse(conn, await queryPromise);
755→          return conn.guildStore.get();
756→        },
757→        onGuildEvent(cb) {
758→          conn.onGuildEvent = cb;
759→        },
760→      };
761→      resolve(handle);
762→    }
763→
764→    login().catch((err) => {
765→      done = true;
766→      clearInterval(pingInterval);
767→      reject(err);
768→      conn.socket?.end();
769→    });
770→
771→    Bun.connect({
772→      hostname: auth.realmHost,
773→      port: auth.realmPort,
774→      socket: {
775→        open(s) {
776→          conn.socket = s;
777→        },
778→        data(_s, data) {
779→          conn.buf.append(new Uint8Array(data));
780→          drainWorldPackets(conn);
781→        },
782→        close() {
783→          clearInterval(pingInterval);
784→          conn.entityStore.clear();
785→          if (!done) reject(new Error("World connection closed"));
786→          closedResolve();
787→        },
788→      },
789→    }).catch(reject);
790→  });
791→}
