 60→  | { type: "invite"; target: string }
 61→  | { type: "kick"; target: string }
 62→  | { type: "leave" }
 63→  | { type: "join_channel"; channel: string; password?: string }
 64→  | { type: "leave_channel"; channel: string }
 65→  | { type: "leader"; target: string }
 66→  | { type: "accept" }
 67→  | { type: "decline" }
 68→  | { type: "nearby" }
 69→  | { type: "nearby_json" }
 70→  | { type: "friends" }
 71→  | { type: "friends_json" }
 72→  | { type: "add_friend"; target: string }
 73→  | { type: "del_friend"; target: string }
 74→  | { type: "ignored" }
 75→  | { type: "ignored_json" }
 76→  | { type: "add_ignore"; target: string }
 77→  | { type: "del_ignore"; target: string }
 78→  | { type: "roll"; min: number; max: number }
 79→  | { type: "guild_roster" }
 80→  | { type: "guild_roster_json" }
 81→  | { type: "unimplemented"; feature: string };
 82→
 83→export function parseIpcCommand(line: string): IpcCommand | undefined {
 84→  if (line.startsWith("/")) {
 85→    const parsed = parseCommand(line);
 86→    switch (parsed.type) {
 87→      case "say":
 88→      case "yell":
 89→      case "guild":
 90→      case "party":
 91→      case "emote":
 92→      case "dnd":
 93→      case "afk":
 94→        return parsed;
 95→      case "whisper":
 96→        return parsed;
 97→      case "who":
 98→        return parsed.target
 99→          ? { type: "who", filter: parsed.target }
100→          : { type: "who" };
101→      case "invite":
102→      case "kick":
103→      case "leave":
104→      case "leader":
105→      case "accept":
106→      case "decline":
107→        return parsed;
108→      case "join-channel":
109→        return {
110→          type: "join_channel",
111→          channel: parsed.channel,
112→          password: parsed.password,
113→        };
114→      case "leave-channel":
115→        return { type: "leave_channel", channel: parsed.channel };
116→      case "friends":
117→        return { type: "friends" };
118→      case "add-friend":
119→        return { type: "add_friend", target: parsed.target };
120→      case "remove-friend":
121→        return { type: "del_friend", target: parsed.target };
122→      case "ignored":
123→        return { type: "ignored" };
124→      case "add-ignore":
125→        return { type: "add_ignore", target: parsed.target };
126→      case "remove-ignore":
127→        return { type: "del_ignore", target: parsed.target };
128→      case "roll":
129→        return parsed;
130→      case "guild-roster":
131→        return { type: "guild_roster" };
132→      case "unimplemented":
133→        return parsed;
134→      default:
135→        return { type: "say", message: line };
136→    }
137→  }
138→
139→  const spaceIdx = line.indexOf(" ");
140→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
141→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
142→
143→  switch (verb) {
144→    case "SAY":
145→    case "YELL":
146→    case "GUILD":
147→    case "PARTY":
148→    case "EMOTE":
149→    case "DND":
150→    case "AFK":
151→      return {
152→        type: verb.toLowerCase() as
153→          | "say"
154→          | "yell"
155→          | "guild"
156→          | "party"
157→          | "emote"
158→          | "dnd"
159→          | "afk",
160→        message: rest,
161→      };
162→    case "WHISPER": {
163→      const targetEnd = rest.indexOf(" ");
164→      if (targetEnd === -1)
165→        return { type: "whisper", target: rest, message: "" };
166→      return {
167→        type: "whisper",
168→        target: rest.slice(0, targetEnd),
169→        message: rest.slice(targetEnd + 1),
170→      };
171→    }
172→    case "READ":
173→      return { type: "read" };
174→    case "READ_JSON":
175→      return { type: "read_json" };
176→    case "READ_WAIT": {
177→      const ms = parseInt(rest, 10);
178→      if (!Number.isFinite(ms) || ms < 0) return undefined;
179→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
180→    }
181→    case "READ_WAIT_JSON": {
182→      const ms = parseInt(rest, 10);
183→      if (!Number.isFinite(ms) || ms < 0) return undefined;
184→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
185→    }
186→    case "STOP":
187→      return { type: "stop" };
188→    case "STATUS":
189→      return { type: "status" };
190→    case "WHO":
191→      return rest ? { type: "who", filter: rest } : { type: "who" };
192→    case "WHO_JSON":
193→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
194→    case "INVITE":
195→      return rest ? { type: "invite", target: rest } : undefined;
196→    case "KICK":
197→      return rest ? { type: "kick", target: rest } : undefined;
198→    case "LEAVE":
199→      if (rest) {
200→        const channel = rest.split(" ")[0]!;
201→        return { type: "leave_channel", channel };
202→      }
203→      return { type: "leave" };
204→    case "LEADER":
205→      return rest ? { type: "leader", target: rest } : undefined;
206→    case "ACCEPT":
207→      return { type: "accept" };
208→    case "DECLINE":
209→      return { type: "decline" };
210→    case "NEARBY":
211→      return { type: "nearby" };
212→    case "NEARBY_JSON":
213→      return { type: "nearby_json" };
214→    case "FRIENDS":
215→      return { type: "friends" };
216→    case "FRIENDS_JSON":
217→      return { type: "friends_json" };
218→    case "ADD_FRIEND":
219→      return rest ? { type: "add_friend", target: rest } : undefined;
220→    case "DEL_FRIEND":
221→      return rest ? { type: "del_friend", target: rest } : undefined;
222→    case "IGNORED":
223→      return { type: "ignored" };
224→    case "IGNORED_JSON":
225→      return { type: "ignored_json" };
226→    case "ADD_IGNORE":
227→      return rest ? { type: "add_ignore", target: rest } : undefined;
228→    case "DEL_IGNORE":
229→      return rest ? { type: "del_ignore", target: rest } : undefined;
230→    case "JOIN": {
231→      if (!rest) return undefined;
232→      const [channel, password] = rest.split(" ") as [string, string?];
233→      return { type: "join_channel", channel, password };
234→    }
235→    case "GUILD_ROSTER":
236→      return { type: "guild_roster" };
237→    case "GUILD_ROSTER_JSON":
238→      return { type: "guild_roster_json" };
239→    case "GINVITE":
240→    case "GKICK":
241→    case "GLEAVE":
242→    case "GPROMOTE":
243→      return { type: "unimplemented", feature: "Guild management" };
244→    case "MAIL":
245→      return { type: "unimplemented", feature: "Mail" };
246→    case "ROLL": {
247→      const parts = rest.split(" ").filter(Boolean);
248→      if (parts.length >= 2)
249→        return {
250→          type: "roll",
251→          min: parseInt(parts[0]!, 10),
252→          max: parseInt(parts[1]!, 10),
253→        };
254→      if (parts.length === 1)
255→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
256→      return { type: "roll", min: 1, max: 100 };
257→    }
258→    default:
259→      return line ? { type: "chat", message: line } : undefined;
260→  }
261→}
262→
263→export function writeLines(socket: IpcSocket, lines: string[]): void {
264→  for (const line of lines) socket.write(line + "\n");
265→  socket.write("\n");
266→}
267→
268→function drainText(events: RingBuffer<EventEntry>): string[] {
269→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
270→}
271→
272→function drainJson(events: RingBuffer<EventEntry>): string[] {
273→  return events.drain().map((e) => e.json);
274→}
275→
276→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
277→  return events
278→    .slice(from)
279→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
280→}
281→
282→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
283→  return events.slice(from).map((e) => e.json);
284→}
285→
286→export async function dispatchCommand(
287→  cmd: IpcCommand,
288→  handle: WorldHandle,
289→  events: RingBuffer<EventEntry>,
290→  socket: IpcSocket,
291→  cleanup: () => void,
292→): Promise<boolean> {
293→  switch (cmd.type) {
294→    case "chat": {
295→      handle.sendInCurrentMode(cmd.message);
296→      const mode = handle.getLastChatMode();
297→      const label =
298→        mode.type === "whisper"
299→          ? `WHISPER ${mode.target}`
300→          : mode.type === "channel"
301→            ? `CHANNEL ${mode.channel}`
302→            : mode.type.toUpperCase();
303→      writeLines(socket, [`OK ${label}`]);
304→      return false;
305→    }
306→    case "say":
307→      handle.sendSay(cmd.message);
308→      writeLines(socket, ["OK"]);
309→      return false;
310→    case "yell":
311→      handle.sendYell(cmd.message);
312→      writeLines(socket, ["OK"]);
313→      return false;
314→    case "guild":
315→      handle.sendGuild(cmd.message);
316→      writeLines(socket, ["OK"]);
317→      return false;
318→    case "party":
319→      handle.sendParty(cmd.message);
320→      writeLines(socket, ["OK"]);
321→      return false;
322→    case "emote":
323→      handle.sendEmote(cmd.message);
324→      writeLines(socket, ["OK"]);
325→      return false;
326→    case "dnd":
327→      handle.sendDnd(cmd.message);
328→      writeLines(socket, ["OK"]);
329→      return false;
330→    case "afk":
331→      handle.sendAfk(cmd.message);
332→      writeLines(socket, ["OK"]);
333→      return false;
334→    case "whisper":
335→      handle.sendWhisper(cmd.target, cmd.message);
336→      writeLines(socket, ["OK"]);
337→      return false;
338→    case "roll":
339→      handle.sendRoll(cmd.min, cmd.max);
340→      writeLines(socket, ["OK"]);
341→      return false;
342→    case "read":
343→      writeLines(socket, drainText(events));
344→      return false;
345→    case "read_json":
346→      writeLines(socket, drainJson(events));
347→      return false;
348→    case "read_wait": {
349→      const start = events.writePos;
350→      await new Promise<void>((resolve) => {
351→        setTimeout(() => {
352→          writeLines(socket, sliceText(events, start));
353→          resolve();
354→        }, cmd.ms);
355→      });
356→      return false;
357→    }
358→    case "read_wait_json": {
359→      const start = events.writePos;
360→      await new Promise<void>((resolve) => {
361→        setTimeout(() => {
362→          writeLines(socket, sliceJson(events, start));
363→          resolve();
364→        }, cmd.ms);
365→      });
366→      return false;
367→    }
368→    case "stop":
369→      writeLines(socket, ["OK"]);
370→      cleanup();
371→      return true;
372→    case "status":
373→      writeLines(socket, ["CONNECTED"]);
374→      return false;
375→    case "who": {
376→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
377→      writeLines(socket, formatWhoResults(results).split("\n"));
378→      return false;
379→    }
380→    case "who_json": {
381→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
382→      writeLines(socket, [formatWhoResultsJson(results)]);
383→      return false;
384→    }
385→    case "invite":
386→      handle.invite(cmd.target);
387→      writeLines(socket, ["OK"]);
388→      return false;
389→    case "kick":
390→      handle.uninvite(cmd.target);
391→      writeLines(socket, ["OK"]);
392→      return false;
393→    case "leave":
394→      handle.leaveGroup();
395→      writeLines(socket, ["OK"]);
396→      return false;
397→    case "leader":
398→      handle.setLeader(cmd.target);
399→      writeLines(socket, ["OK"]);
400→      return false;
401→    case "accept":
402→      handle.acceptInvite();
403→      writeLines(socket, ["OK"]);
404→      return false;
405→    case "decline":
406→      handle.declineInvite();
407→      writeLines(socket, ["OK"]);
408→      return false;
409→    case "nearby": {
410→      const entities = handle.getNearbyEntities();
411→      writeLines(socket, entities.map(formatNearbyLine));
412→      return false;
413→    }
414→    case "nearby_json": {
415→      const entities = handle.getNearbyEntities();
416→      writeLines(
417→        socket,
418→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
419→      );
420→      return false;
421→    }
422→    case "friends": {
423→      const friends = handle.getFriends();
424→      writeLines(socket, formatFriendList(friends).split("\n"));
425→      return false;
426→    }
427→    case "friends_json": {
428→      const friends = handle.getFriends();
429→      writeLines(socket, [formatFriendListJson(friends)]);
430→      return false;
431→    }
432→    case "add_friend":
433→      handle.addFriend(cmd.target);
434→      writeLines(socket, ["OK"]);
435→      return false;
436→    case "del_friend":
437→      handle.removeFriend(cmd.target);
438→      writeLines(socket, ["OK"]);
439→      return false;
440→    case "ignored": {
441→      const ignored = handle.getIgnored();
442→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
443→      return false;
444→    }
445→    case "ignored_json": {
446→      const ignored = handle.getIgnored();
447→      writeLines(socket, [formatIgnoreListJson(ignored)]);
448→      return false;
449→    }
450→    case "add_ignore":
451→      handle.addIgnore(cmd.target);
452→      writeLines(socket, ["OK"]);
453→      return false;
454→    case "del_ignore":
455→      handle.removeIgnore(cmd.target);
456→      writeLines(socket, ["OK"]);
457→      return false;
458→    case "join_channel":
459→      handle.joinChannel(cmd.channel, cmd.password);
460→      writeLines(socket, ["OK"]);
461→      return false;
462→    case "leave_channel":
463→      handle.leaveChannel(cmd.channel);
464→      writeLines(socket, ["OK"]);
465→      return false;
466→    case "guild_roster": {
467→      const roster = await handle.requestGuildRoster();
468→      if (roster) {
469→        writeLines(socket, formatGuildRoster(roster).split("\n"));
470→      } else {
471→        writeLines(socket, ["[guild] No guild roster available"]);
472→      }
473→      return false;
474→    }
475→    case "guild_roster_json": {
476→      const roster = await handle.requestGuildRoster();
477→      if (roster) {
478→        writeLines(socket, [formatGuildRosterJson(roster)]);
479→      } else {
480→        writeLines(socket, [
481→          JSON.stringify({ type: "GUILD_ROSTER", members: [] }),
482→        ]);
483→      }
484→      return false;
485→    }
486→    case "unimplemented":
487→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
488→      return false;
489→  }
490→}
491→
492→function objectTypeName(type: ObjectType): string {
493→  switch (type) {
494→    case ObjectType.UNIT:
495→      return "NPC";
496→    case ObjectType.PLAYER:
497→      return "Player";
498→    default:
499→      return `type ${type}`;
500→  }
501→}
502→
503→function formatNearbyLine(entity: Entity): string {
504→  if (
505→    entity.objectType === ObjectType.UNIT ||
506→    entity.objectType === ObjectType.PLAYER
507→  ) {
508→    const unit = entity as UnitEntity;
509→    const name = entity.name ?? "Unknown";
510→    const kind = objectTypeName(entity.objectType);
511→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
512→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
513→    const pos = entity.position
514→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
515→      : "";
516→    return `${name} (${kind}${level}) ${hp}${pos}`;
517→  }
518→  if (entity.objectType === ObjectType.GAMEOBJECT) {
519→    const name = entity.name ?? "Unknown";
520→    const pos = entity.position
521→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
522→      : "";
523→    return `${name} (GameObject)${pos}`;
524→  }
525→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
526→}
527→
528→function objectTypeString(type: ObjectType): string {
529→  switch (type) {
530→    case ObjectType.UNIT:
531→      return "unit";
532→    case ObjectType.PLAYER:
533→      return "player";
534→    case ObjectType.GAMEOBJECT:
535→      return "gameobject";
536→    default:
537→      return "object";
538→  }
539→}
540→
541→function formatNearbyObj(entity: Entity): Record<string, unknown> {
542→  const obj: Record<string, unknown> = {
543→    guid: `0x${entity.guid.toString(16)}`,
544→    type: objectTypeString(entity.objectType),
545→    name: entity.name,
546→  };
547→  if (
548→    entity.objectType === ObjectType.UNIT ||
549→    entity.objectType === ObjectType.PLAYER
550→  ) {
551→    const unit = entity as UnitEntity;
552→    obj["level"] = unit.level;
553→    obj["health"] = unit.health;
554→    obj["maxHealth"] = unit.maxHealth;
555→  }
556→  if (entity.objectType === ObjectType.GAMEOBJECT) {
557→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
558→  }
559→  if (entity.position) {
560→    obj["x"] = entity.position.x;
561→    obj["y"] = entity.position.y;
562→    obj["z"] = entity.position.z;
563→  }
564→  return obj;
565→}
566→
567→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
568→  switch (event.type) {
569→    case "invite_received":
570→      return { type: "GROUP_INVITE", from: event.from };
571→    case "command_result":
572→      return {
573→        type: "GROUP_COMMAND_RESULT",
574→        operation: event.operation,
575→        target: event.target,
576→        result: event.result,
577→      };
578→    case "leader_changed":
579→      return { type: "GROUP_LEADER_CHANGED", name: event.name };
580→    case "group_destroyed":
581→      return { type: "GROUP_DESTROYED" };
582→    case "kicked":
583→      return { type: "GROUP_KICKED" };
584→    case "invite_declined":
585→      return { type: "GROUP_INVITE_DECLINED", name: event.name };
586→    case "group_list":
587→      return {
588→        type: "GROUP_LIST",
589→        members: event.members.map((m) => ({
590→          name: m.name,
591→          online: m.online,
592→        })),
593→        leader: event.leader,
594→      };
595→    case "member_stats":
596→      return {
597→        type: "PARTY_MEMBER_STATS",
598→        guidLow: event.guidLow,
599→        online: event.online,
600→        hp: event.hp,
601→        maxHp: event.maxHp,
602→        level: event.level,
603→      };
604→  }
605→}
606→
607→export function onGroupEvent(
608→  event: GroupEvent,
609→  events: RingBuffer<EventEntry>,
610→  log: SessionLog,
611→): void {
612→  const text = formatGroupEvent(event);
613→  const obj = formatGroupEventObj(event);
614→  events.push({ text, json: JSON.stringify(obj) });
615→  log.append(obj as LogEntry).catch(() => {});
616→}
617→
618→export function onChatMessage(
619→  msg: ChatMessage,
620→  events: RingBuffer<EventEntry>,
621→  log: SessionLog,
622→): void {
623→  const obj = formatMessageObj(msg);
624→  events.push({ text: formatMessage(msg), json: JSON.stringify(obj) });
625→  log.append(obj).catch(() => {});
626→}
627→
628→export function onEntityEvent(
629→  event: EntityEvent,
630→  events: RingBuffer<EventEntry>,
631→  log: SessionLog,
632→): void {
633→  const text = formatEntityEvent(event);
634→  const obj = formatEntityEventObj(event);
635→  if (obj) {
636→    events.push({ text, json: JSON.stringify(obj) });
637→    log.append(obj as LogEntry).catch(() => {});
638→  }
639→}
640→
641→export function onFriendEvent(
642→  event: FriendEvent,
643→  events: RingBuffer<EventEntry>,
644→  log: SessionLog,
645→): void {
646→  const text = formatFriendEvent(event);
647→  const obj = formatFriendEventObj(event);
648→  if (obj) {
649→    events.push({ text, json: JSON.stringify(obj) });
650→    log.append(obj as LogEntry).catch(() => {});
651→  }
652→}
