654→export function onIgnoreEvent(
655→  event: IgnoreEvent,
656→  events: RingBuffer<EventEntry>,
657→  log: SessionLog,
658→): void {
659→  const text = formatIgnoreEvent(event);
660→  const obj = formatIgnoreEventObj(event);
661→  if (obj) {
662→    events.push({ text, json: JSON.stringify(obj) });
663→    log.append(obj as LogEntry).catch(() => {});
664→  }
665→}
666→
667→export function onGuildEvent(
668→  event: GuildEvent,
669→  events: RingBuffer<EventEntry>,
670→  log: SessionLog,
671→): void {
672→  const roster = event.roster;
673→  const text = `[guild] Roster updated: ${roster.members.length} members`;
674→  const obj = {
675→    type: "GUILD_ROSTER_UPDATED",
676→    sender: "",
677→    message: `${roster.members.length} members`,
678→  };
